+
+function isInternalFrame(line: string, mode: NormalizedErrorStackOptions['stripInternalFrames']) {
+  return (
+    (mode === 'node' || mode === 'node_and_superjson') && line.includes('node:internal') ||
+    (mode === 'superjson' || mode === 'node_and_superjson') &&
+      (line.includes('src/transformer.ts') || line.includes('src/plainer.ts') || line.includes('src/index.ts'))
+  );
+}
+
+function redactPath(line: string, mode: NormalizedErrorStackOptions['redactPaths']): string {
+  if (mode === 'strip_cwd') {
+    const cwd = process.cwd().replace(/\\\\/g, '/');
+    return line.replaceAll(cwd, '').replaceAll(cwd.replace(/\\//g, '\\\'), '');
+  }
+  if (mode === 'basename') {
+    return line.replace(/(?:file:\\/\\/)?(?:[A-Za-z]:)?[\\\\/](?:[^\\s():\\\\/]+[\\\\/])*([^\\s():\\\\/]+)(?=:\\d|\\)|\\s|$)/g, '$1');
+  }
+  return line;
