+function stackLines(stack: string, options: NormalizedErrorStackOptions, frames: boolean): string[] {
+  const source = options.normalizeNewlines ? normalizeStackNewlines(stack) : stack;
+  let lines = source.split('\
').map((line, index) =>
+    index > 0 && options.trimLeadingWhitespace ? line.replace(/^\\s+/, '') : line
+  );
+  if (frames) {
+    lines = [lines[0], ...lines.slice(1).filter(line => !isInternalFrame(line, options.stripInternalFrames))];
+    lines = lines.map(line => redactPath(line, options.redactPaths));
+  } else {
+    lines = lines.map(line => redactPath(line, options.redactPaths));
+    lines = options.maxStackLines ? lines.slice(0, options.maxStackLines) : lines;
+    lines = [lines[0], ...lines.slice(1).filter(line => !isInternalFrame(line, options.stripInternalFrames))];
+    return lines;
+  }
+  return options.maxStackLines ? lines.slice(0, options.maxStackLines) : lines;
